index fdef49e310f8..1b56c8f7f014 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -841,6 +841,26 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
       Value *And = Builder.CreateAnd(X, Builder.CreateOr(MaskC, One));
       return new ICmpInst(ICmpInst::ICMP_NE, And, Zero);
     }
+    {
+      const APInt *C;
+      if (match(Src, m_Shr(m_APInt(C), m_Value(X)))) {
+        // trunc (shr C, X) to i1 --> (C >> X) & 1 != 0
+        if (C->isZero())
+          return replaceInstUsesWith(Trunc, ConstantInt::getFalse(DestTy));
+        // If C is a power of two, then this is X == log2(C).
+        if (C->isPowerOf2()) {
+          Constant *Log2C = ConstantInt::get(SrcTy, C->exactLogBase2());
+          return new ICmpInst(ICmpInst::ICMP_EQ, X, Log2C);
+        }
+        // If C is a mask of lower bits, then this is X < number of trailing ones.
+        if (C->isMask()) {
+          unsigned N = C->countTrailingOnes();
+          Constant *NConst = ConstantInt::get(SrcTy, N);
+          return new ICmpInst(ICmpInst::ICMP_ULT, X, NConst);
+        }
+      }
+    }
+

